import { Types } from "mongoose";
import SoftDeleteAdminResourceAction from "@/actions/admin/SoftDeleteAdminResource.action";

const createContentRepository = () =>
  ({
    findById: jest.fn().mockResolvedValue({ _id: new Types.ObjectId() }),
    updateOne: jest.fn(),
  }) as any;

describe("Admin moderation", () => {
  it("soft deletes content without hard deletion", async () => {
    const eventRepository = createContentRepository();
    const action = new SoftDeleteAdminResourceAction(
      eventRepository,
      createContentRepository(),
      createContentRepository(),
      createContentRepository(),
      createContentRepository()
    );

    await action.execute({
      adminId: new Types.ObjectId().toString(),
      resource: "events",
      resourceId: new Types.ObjectId().toString(),
      deleted: true,
      reason: "Moderation",
    });

    expect(eventRepository.updateOne).toHaveBeenCalledWith(
      expect.any(String),
      expect.objectContaining({ deleted: true, deleteReason: "Moderation" })
    );
    expect(eventRepository.deleteOne).toBeUndefined();
  });
});

import { CreateEventAction } from "@/actions/events";
import { IEventRepository } from "@/types/repositories/event.repository.types";
import { IPlaceRepository } from "@/types/repositories/place.repository.types";
import { Types } from "mongoose";
import { ERROR_CODES } from "@/utils/errors";
import {
  buildCreateEventData,
  createMockRepository,
} from "../../helpers/mockRepositories";

describe("CreateEventAction", () => {
  let eventRepository: jest.Mocked<IEventRepository>;
  let placeRepository: jest.Mocked<IPlaceRepository>;
  let action: CreateEventAction;

  beforeEach(() => {
    eventRepository = createMockRepository<IEventRepository>(
      "aggregate",
      "updateMany"
    );
    placeRepository = createMockRepository<IPlaceRepository>("aggregate");
    action = new CreateEventAction(eventRepository, placeRepository);
  });

  it("creates an event with an owned place", async () => {
    const userId = new Types.ObjectId().toString();
    const placeId = new Types.ObjectId().toString();
    const eventId = new Types.ObjectId();

    placeRepository.findById.mockResolvedValue({
      _id: new Types.ObjectId(placeId),
      user: new Types.ObjectId(userId),
    } as any);
    eventRepository.create.mockResolvedValue(eventId);

    const result = await action.execute({
      eventData: buildCreateEventData({
        user: userId,
        place: placeId,
        online: false,
      }),
    });

    expect(result).toEqual({ _id: eventId.toString() });
    expect(placeRepository.findById).toHaveBeenCalledWith(placeId, ["user"]);
    expect(eventRepository.create).toHaveBeenCalledWith(
      expect.objectContaining({
        user: userId,
        place: placeId,
        location: null,
        online: false,
        deleted: false,
      })
    );
  });

  it("rejects an event with a place owned by another user", async () => {
    const userId = new Types.ObjectId().toString();
    const placeId = new Types.ObjectId().toString();

    placeRepository.findById.mockResolvedValue({
      _id: new Types.ObjectId(placeId),
      user: new Types.ObjectId(),
    } as any);

    await expect(
      action.execute({
        eventData: buildCreateEventData({
          user: userId,
          place: placeId,
          online: false,
        }),
      })
    ).rejects.toMatchObject({
      code: ERROR_CODES.EVENT_PLACE_FORBIDDEN,
      statusCode: 403,
    });

    expect(eventRepository.create).not.toHaveBeenCalled();
  });
});

import { IUserRepository } from "@/types/repositories/user.repository.types";
import { generateToken } from "@/utils/jwt";
import { getBanMessage, isBanActive } from "@/utils/ban";
import { ERROR_CODES, ForbiddenError, UnauthorizedError } from "@/utils/errors";
import bcrypt from "bcrypt";

export interface SignInInput {
  identifier: string;
  password: string;
}

export interface ISignInAction {
  execute(params: {
    signInData: SignInInput;
  }): Promise<{ user: any; token: string }>;
}

class SignInAction implements ISignInAction {
  constructor(private userRepository: IUserRepository) {}

  async execute({
    signInData,
  }: {
    signInData: SignInInput;
  }): Promise<{ user: any; token: string }> {
    const { identifier, password } = signInData;

    const user = await this.userRepository.findOne(
      { $or: [{ email: identifier }, { username: identifier }] },
      [
        "_id",
        "email",
        "username",
        "password",
        "userType",
        "role",
        "deleted",
        "emailVerified",
        "bannedAt",
        "banReason",
        "banExpiresAt",
      ]
    );

    if (!user) {
      throw new UnauthorizedError(
        ERROR_CODES.AUTH_INVALID_CREDENTIALS,
        "Les identifiants sont incorrects"
      );
    }
    if (!password || !(await bcrypt.compare(password, user.password))) {
      throw new UnauthorizedError(
        ERROR_CODES.AUTH_INVALID_CREDENTIALS,
        "Les identifiants sont incorrects"
      );
    }

    if (user.emailVerified === false) {
      throw new ForbiddenError(
        ERROR_CODES.AUTH_EMAIL_NOT_VERIFIED,
        "Veuillez vérifier votre adresse email avant de vous connecter. Consultez votre boîte de réception ou demandez un nouveau lien."
      );
    }
    if (user.deleted) {
      throw new ForbiddenError(
        ERROR_CODES.AUTH_ACCOUNT_INACCESSIBLE,
        "Ce compte n'est plus accessible"
      );
    }
    if (isBanActive(user)) {
      throw new ForbiddenError(ERROR_CODES.AUTH_USER_BANNED, getBanMessage(user));
    }

    await this.userRepository.updateOne(user._id.toString(), {
      lastLogin: new Date(),
    });

    const token = generateToken({
      id: user._id.toString(),
      userType: user.userType,
      role: user.role,
    });

    return {
      user: {
        _id: user._id,
        email: user.email,
        username: user.username,
        userType: user.userType,
        role: user.role,
      },
      token,
    };
  }
}

export default SignInAction;

import { IEventBookingRepository } from "@/types/repositories/eventBooking.repository.types";
import { IEventRepository } from "@/types/repositories/event.repository.types";
import {
  ConflictError,
  ERROR_CODES,
  ForbiddenError,
  NotFoundError,
  ValidationError,
} from "@/utils/errors";
import { toId } from "@/utils/mongoose";

export interface CreateEventBookingDTO {
  eventId: string;
  userId: string;
  seats: number;
}

export interface ICreateEventBookingAction {
  execute(params: CreateEventBookingDTO): Promise<{ _id: string }>;
}

class CreateEventBookingAction implements ICreateEventBookingAction {
  constructor(
    private eventBookingRepository: IEventBookingRepository,
    private eventRepository: IEventRepository
  ) {}

  async execute({
    eventId,
    userId,
    seats,
  }: CreateEventBookingDTO): Promise<{ _id: string }> {
    const event = await this.eventRepository.findById(eventId, [
      "_id",
      "user",
      "deleted",
      "isBookable",
      "capacity",
      "maxSeatsPerBooking",
      "lifecycleStatus",
    ]);

    if (!event || event.deleted) {
      throw new NotFoundError(ERROR_CODES.EVENT_NOT_FOUND, "Event not found");
    }

    if (!event.isBookable) {
      throw new ForbiddenError(
        ERROR_CODES.EVENT_NOT_BOOKABLE,
        "Cet évènement n'est pas réservable"
      );
    }

    if (event.lifecycleStatus !== "upcoming") {
      throw new ForbiddenError(
        ERROR_CODES.EVENT_BOOKING_CLOSED,
        "Cet évènement a déjà commencé ou est terminé, la réservation n'est plus possible"
      );
    }

    const eventOwnerId = toId(event.user);
    if (eventOwnerId === userId) {
      throw new ForbiddenError(
        ERROR_CODES.EVENT_BOOKING_OWN_EVENT,
        "Vous ne pouvez pas réserver votre propre évènement"
      );
    }

    const existingBooking = await this.eventBookingRepository.findOne({
      event: eventId as any,
      user: userId as any,
      status: "confirmed",
    });

    if (existingBooking) {
      throw new ConflictError(
        ERROR_CODES.EVENT_BOOKING_ALREADY_EXISTS,
        "Vous avez déjà une réservation pour cet évènement"
      );
    }

    if (seats > event.maxSeatsPerBooking) {
      throw new ValidationError(
        { seats: `Maximum ${event.maxSeatsPerBooking} place(s)` },
        ERROR_CODES.EVENT_BOOKING_TOO_MANY_SEATS,
        `Vous ne pouvez pas réserver plus de ${event.maxSeatsPerBooking} place(s)`
      );
    }

    if (typeof event.capacity === "number") {
      const bookedSeats = await this.eventBookingRepository.sumConfirmedSeats(
        eventId
      );
      if (bookedSeats + seats > event.capacity) {
        throw new ConflictError(
          ERROR_CODES.EVENT_BOOKING_NOT_ENOUGH_SEATS,
          "Il ne reste plus assez de places disponibles"
        );
      }
    }

    const bookingId = await this.eventBookingRepository.create({
      event: eventId as any,
      user: userId as any,
      seats,
      status: "confirmed",
    });

    return { _id: bookingId.toString() };
  }
}

export default CreateEventBookingAction;

