import {
  IEventInvitationRepository,
  EventInvitationFilters,
} from "@/types/repositories/eventInvitation.repository.types";
import { IEventInvitation } from "@/types/models/eventInvitation";

export interface GetEventInvitationsInput {
  eventId: string;
  currentUserId?: string;
  onlyAccepted?: boolean;
}

export interface IGetEventInvitationsAction {
  execute(params: {
    filters: GetEventInvitationsInput;
  }): Promise<IEventInvitation[]>;
}

class GetEventInvitationsAction implements IGetEventInvitationsAction {
  private readonly project: (keyof IEventInvitation | string)[] = [
    "_id",
    "initiator",
    "collaborator",
    "status",
    "deleted",
    "initiator._id",
    "collaborator._id",
    "collaborator.username",
    "collaborator.userCategory",
    "collaborator.image",
    "collaborator.deleted",
    "collaborator.image.urls",
    "collaborator.googlePictureUrl",
    "collaborator.userCategory.name",
  ];

  constructor(private eventInvitationRepository: IEventInvitationRepository) {}

  async execute({
    filters,
  }: {
    filters: GetEventInvitationsInput;
  }): Promise<IEventInvitation[]> {
    const queryFilters: EventInvitationFilters = {
      event: filters.eventId,
      deleted: false,
    };

    const eventInvitations = await this.eventInvitationRepository.findAll({
      filters: queryFilters,
      project: this.project,
    });

    const filteredInvitations = eventInvitations.filter((invitation: any) => {
      if (!filters.currentUserId || filters.onlyAccepted) {
        return invitation.status === "accepted";
      }
      const isInitiator =
        invitation.initiator &&
        (typeof invitation.initiator === "object"
          ? invitation.initiator._id?.toString()
          : invitation.initiator.toString()) === filters.currentUserId;
      const isCollaborator =
        invitation.collaborator &&
        (typeof invitation.collaborator === "object"
          ? invitation.collaborator._id?.toString()
          : invitation.collaborator.toString()) === filters.currentUserId;

      if (isInitiator || isCollaborator) {
        return true;
      }
      return invitation.status === "accepted";
    });

    return filteredInvitations as IEventInvitation[];
  }
}

export default GetEventInvitationsAction;

import { IEventRepository } from "@/types/repositories/event.repository.types";
import { IEventBookingRepository } from "@/types/repositories/eventBooking.repository.types";
import { IEvent } from "@/types/models/event";

export interface IGetEventByIdAction {
  execute(params: { eventId: string }): Promise<IEvent>;
}

class GetEventByIdAction implements IGetEventByIdAction {
  private readonly defaultProject: (keyof IEvent | string)[] = [
    "_id",
    "name",
    "description",
    "status",
    "lifecycleStatus",
    "schedule",
    "dateRange",
    "eventCategory",
    "eventCategory.name",
    "place",
    "user",
    "location",
    "online",
    "image",
    "rating",
    "isBookable",
    "capacity",
    "maxSeatsPerBooking",
    "createdAt",
    "updatedAt",
    "place._id",
    "place.location",
    "place.user",
    "place.user.username",
    "user._id",
    "user.username",
    "user.image",
    "user.image.urls",
    "image._id",
    "image.urls",
    "deleted",
    "schedule.timeSlots.collaborators",
    "schedule.timeSlots.collaborators._id",
    "schedule.timeSlots.collaborators.username",
    "schedule.timeSlots.collaborators.image",
    "schedule.timeSlots.collaborators.image.urls",
  ];

  constructor(
    private eventRepository: IEventRepository,
    private eventBookingRepository: IEventBookingRepository
  ) {}

  async execute({ eventId }: { eventId: string }): Promise<IEvent> {
    const event = await this.eventRepository.findById(
      eventId,
      this.defaultProject
    );

    if (!event || event.deleted) {
      throw new Error("Event not found");
    }

    let bookedSeats: number | undefined;
    let remainingSeats: number | null | undefined;

    if (event.isBookable) {
      bookedSeats = await this.eventBookingRepository.sumConfirmedSeats(
        eventId
      );
      remainingSeats =
        typeof event.capacity === "number"
          ? Math.max(event.capacity - bookedSeats, 0)
          : null;
    }

    const updatedEvent = {
      ...event,
      bookedSeats,
      remainingSeats,
      schedule: event.schedule.map((period) => ({
        ...period,
        timeSlots: period.timeSlots?.map((slot) => ({
          ...slot,
          collaborators: slot.collaborators.map((collaborator: any) => {
            if (typeof collaborator === "object" && collaborator !== null) {
              return {
                name: collaborator.username,
                image: collaborator.image?.urls?.thumbnail || null,
                _id: collaborator._id,
              };
            }
            return collaborator;
          }),
        })),
      })),
    };

    return updatedEvent as IEvent;
  }
}

export default GetEventByIdAction;

import { IFollowRepository } from "@/types/repositories/follow.repository.types";
import { IFollow } from "@/types/models/follow";
import { Types } from "mongoose";
import FollowService from "@/services/followService";
import NotificationService from "@/services/notificationService";

export interface ICreateFollowAction {
  execute(params: {
    followerId: string;
    followingId: string;
  }): Promise<{ _id: string }>;
}

class CreateFollowAction implements ICreateFollowAction {
  private followService: FollowService;

  constructor(
    private followRepository: IFollowRepository,
    followService: FollowService,
    private notificationService: NotificationService
  ) {
    this.followService = followService;
  }

  async execute({
    followerId,
    followingId,
  }: {
    followerId: string;
    followingId: string;
  }): Promise<{ _id: string }> {
    if (followerId === followingId) {
      throw new Error("You cannot follow yourself");
    }
    const existingFollow = await this.followRepository.findOne({
      follower: new Types.ObjectId(followerId),
      following: new Types.ObjectId(followingId),
    } as any);

    if (existingFollow) {
      throw new Error("You are already following this user");
    }

    const followId = await this.followRepository.create({
      follower: new Types.ObjectId(followerId),
      following: new Types.ObjectId(followingId),
    } as Partial<IFollow>);

    await this.followService.incrementFollowersCount(followingId);

    await this.notificationService.createNotification({
      sender: followerId,
      receiver: followingId,
      action: "new_follower",
      reference: followId.toString(),
      referenceType: "Follow",
    });

    return { _id: followId.toString() };
  }
}

export default CreateFollowAction;

