import { IImageRepository } from "@/types/repositories/image.repository.types";
import AwsService from "@/services/awsService";
import logger from "@/utils/logger";

export interface IDeleteImagesAction {
  execute(params: { imageIds: string[] }): Promise<void>;
}

class DeleteImagesAction implements IDeleteImagesAction {
  private awsService: AwsService;

  constructor(private imageRepository: IImageRepository) {
    this.awsService = new AwsService();
  }

  async execute({ imageIds }: { imageIds: string[] }): Promise<void> {
    if (imageIds.length === 0) return;

    const images = await this.imageRepository.findAll({
      filters: { _id: { $in: imageIds } },
      project: ["_id", "urls"],
    });

    await this.imageRepository.deleteMany(imageIds);

    await Promise.allSettled(
      images.map(async (image: any) => {
        if (!image.urls) {
          logger.warn(`No URLs found for image ${image._id}`);
          return;
        }
        const deleteResults = await Promise.allSettled([
          this.awsService.deleteObjectFromS3(image.urls.original),
          this.awsService.deleteObjectFromS3(image.urls.thumbnail),
          this.awsService.deleteObjectFromS3(image.urls.medium),
        ]);
        const successfulDeletions = deleteResults.filter(
          (result) => result.status === "fulfilled" && result.value
        ).length;

        logger.info(
          `Image ${image._id}: ${successfulDeletions}/3 files deleted from S3`
        );
      })
    );

    logger.info(
      `Successfully deleted ${imageIds.length} images from database and S3`
    );
  }
}

export default DeleteImagesAction;

import { IImageRepository } from "@/types/repositories/image.repository.types";
import AwsService, { ProcessedImageUrls } from "@/services/awsService";
import { Types } from "mongoose";
import { IImage } from "@/types/models/Image";

export interface UploadImageInput {
  file: Express.Multer.File;
  reference: string;
  referenceType: string;
  type: string;
  userId: string;
}

export interface IUploadImagesAction {
  execute(params: { images: UploadImageInput[] }): Promise<IImage[]>;
}

class UploadImagesAction implements IUploadImagesAction {
  private awsService: AwsService;

  constructor(private imageRepository: IImageRepository) {
    this.awsService = new AwsService();
  }

  async execute({ images }: { images: UploadImageInput[] }): Promise<IImage[]> {
    const imageResults = await Promise.all(
      images.map(async (input) => {
        const processedUrls = (await this.awsService.uploadToS3(
          input.file.buffer,
          "", // key not needed for images as it's generated automatically
          input.file.mimetype,
          input.file.originalname
        )) as ProcessedImageUrls;

        return {
          urls: processedUrls,
          user: new Types.ObjectId(input.userId),
          referenceType: input.referenceType,
          reference: new Types.ObjectId(input.reference),
          type: input.type,
          originalName: input.file.originalname,
          size: input.file.size,
          mimetype: input.file.mimetype,
        };
      })
    );

    const imageIds = await this.imageRepository.createMany(
      imageResults as unknown as Partial<IImage>[]
    );

    const createdImages = await this.imageRepository.findAll({
      filters: { _id: { $in: imageIds.map((id) => id.toString()) } },
      project: [
        "_id",
        "urls",
        "user",
        "reference",
        "referenceType",
        "type",
        "originalName",
        "size",
        "mimetype",
        "createdAt",
        "updatedAt",
      ],
    });

    const imagesWithSignedUrls = await Promise.all(
      createdImages.map(async (image: any) => {
        const signedUrls = {
          original: await this.awsService.generateSignedUrlFromFullUrl(
            image.urls.original
          ),
          thumbnail: await this.awsService.generateSignedUrlFromFullUrl(
            image.urls.thumbnail
          ),
          medium: await this.awsService.generateSignedUrlFromFullUrl(
            image.urls.medium
          ),
        };
        return {
          ...image,
          signedUrls: signedUrls,
        };
      })
    );

    return imagesWithSignedUrls as IImage[];
  }
}

export default UploadImagesAction;

import { IMessageRepository } from "@/types/repositories/message.repository.types";
import { IConversationRepository } from "@/types/repositories/conversation.repository.types";
import { CreateMessageInput } from "../../validations/message.validations";
import { Types } from "mongoose";
import { IMessage } from "@/types/models/message";

export interface ICreateMessageAction {
  execute(params: {
    messageData: CreateMessageInput;
    senderId: string;
  }): Promise<{
    _id: string;
    conversationId: string;
    message: Partial<IMessage>;
  }>;
}

class CreateMessageAction implements ICreateMessageAction {
  private readonly project: (keyof IMessage | string)[] = [
    "_id",
    "conversation",
    "sender",
    "sender.username",
    "sender.image.urls",
    "content",
    "readBy",
    "createdAt",
    "updatedAt",
  ];

  constructor(
    private messageRepository: IMessageRepository,
    private conversationRepository: IConversationRepository
  ) {}

  async execute({
    messageData,
    senderId,
  }: {
    messageData: CreateMessageInput;
    senderId: string;
  }): Promise<{
    _id: string;
    conversationId: string;
    message: Partial<IMessage>;
  }> {
    const { recipientId, content } = messageData;

    const senderObjectId = new Types.ObjectId(senderId);
    const recipientObjectId = new Types.ObjectId(recipientId);

    let conversation = await this.conversationRepository.findOne({
      participants: {
        $all: [senderId, recipientId],
      },
    } as any);

    if (!conversation) {
      const conversationId = await this.conversationRepository.create({
        participants: [senderObjectId, recipientObjectId],
      });
      conversation = await this.conversationRepository.findById(
        conversationId.toString()
      );
    }

    if (!conversation) {
      throw new Error("Failed to create or find conversation");
    }

    const messageId = await this.messageRepository.create({
      conversation: conversation._id,
      sender: senderObjectId,
      content,
      readBy: [],
    });

    await this.conversationRepository.updateOne(conversation._id.toString(), {
      lastMessage: messageId,
    });

    const message = await this.messageRepository.findById(
      messageId.toString(),
      this.project
    );

    return {
      _id: messageId.toString(),
      conversationId: conversation._id.toString(),
      message: message || {},
    };
  }
}

export default CreateMessageAction;

