import { IMessageRepository } from "@/types/repositories/message.repository.types";
import { IConversationRepository } from "@/types/repositories/conversation.repository.types";
import { Types } from "mongoose";
import { IConversation } from "@/types/models/conversation";

export interface Conversation {
  _id: string;
  participants: {
    _id: string;
    username?: string;
    firstname?: string;
    lastname?: string;
    email?: string;
    image?: {
      urls: {
        thumbnail: string;
        medium: string;
      };
    };
  }[];
  lastMessage: {
    content?: string;
    partnership?:
      | string
      | {
          type?: "place" | "event";
        };
    createdAt: Date | string;
  };
  unreadCount: number;
}

export interface IGetConversationsAction {
  execute(params: { userId: string }): Promise<Conversation[]>;
}

class GetConversationsAction implements IGetConversationsAction {
  private readonly conversationProject: (keyof IConversation | string)[] = [
    "_id",
    "participants",
    "participants._id",
    "participants.username",
    "participants.firstname",
    "participants.lastname",
    "participants.email",
    "participants.image.urls",
    "lastMessage",
    "lastMessage.content",
    "lastMessage.partnership",
    "lastMessage.partnership.type",
    "lastMessage.createdAt",
    "updatedAt",
  ];
  constructor(
    private conversationRepository: IConversationRepository,
    private messageRepository: IMessageRepository
  ) {}

  async execute({ userId }: { userId: string }): Promise<Conversation[]> {
    const conversations = await this.conversationRepository.findAll({
      filters: {
        participants: userId,
      },
      project: this.conversationProject,
      sort: { updatedAt: -1 },
    });

    const result: Conversation[] = [];

    for (const conversation of conversations) {
      const unreadCount = await this.messageRepository.countAll({
        filters: {
          conversation: conversation._id.toString(),
          readBy: { $nin: [new Types.ObjectId(userId)] },
          sender: { $ne: new Types.ObjectId(userId) },
        },
      });

      (conversation as any).unreadCount = unreadCount;

      result.push(conversation as unknown as Conversation);
    }

    return result;
  }
}

export default GetConversationsAction;

import { IPartnershipRepository } from "@/types/repositories/partnership.repository.types";
import { IPartnership } from "@/types/models/partnership";
import { PartnershipDTO } from "@/types/api/partnership.dto";
import { Types } from "mongoose";
import NotificationService from "@/services/notificationService";
import {
  AppError,
  ConflictError,
  ERROR_CODES,
  ValidationError,
} from "@/utils/errors";

export interface ICreatePartnershipsAction {
  execute(params: {
    partnership: PartnershipDTO;
    initiatorId: string;
  }): Promise<IPartnership>;
}

class CreatePartnershipsAction implements ICreatePartnershipsAction {
  constructor(
    private partnershipRepository: IPartnershipRepository,
    private notificationService: NotificationService
  ) {}

  async execute({
    partnership,
    initiatorId,
  }: {
    partnership: PartnershipDTO;
    initiatorId: string;
  }): Promise<IPartnership> {
    const collaboratorId = partnership.collaborator._id;
    if (!collaboratorId) {
      throw new ValidationError(
        { collaborator: "Collaborator ID is required" },
        ERROR_CODES.PARTNERSHIP_COLLABORATOR_REQUIRED,
        "Collaborator ID is required"
      );
    }

    const initiatorObjectId = new Types.ObjectId(initiatorId);
    const collaboratorObjectId = new Types.ObjectId(collaboratorId);

    const existingPartnership = await this.partnershipRepository.findOne({
      deleted: false,
      $or: [
        {
          initiator: initiatorObjectId,
          collaborator: collaboratorObjectId,
        },
        {
          initiator: collaboratorObjectId,
          collaborator: initiatorObjectId,
        },
      ],
    } as any);

    if (existingPartnership) {
      throw new ConflictError(
        existingPartnership.status === "accepted"
          ? ERROR_CODES.PARTNERSHIP_ALREADY_EXISTS
          : ERROR_CODES.PARTNERSHIP_INVITATION_ALREADY_SENT,
        existingPartnership.status === "accepted"
          ? "Vous avez déjà une collaboration avec cet utilisateur"
          : "Invitation déjà envoyée"
      );
    }

    const partnershipId = await this.partnershipRepository.create({
      initiator: initiatorObjectId,
      collaborator: collaboratorObjectId,
      status: "pending",
      deleted: false,
    } as Partial<IPartnership>);

    const newPartnership = await this.partnershipRepository.findById(
      partnershipId.toString()
    );

    if (!newPartnership) {
      throw new AppError(
        ERROR_CODES.PARTNERSHIP_CREATE_FAILED,
        500,
        "Failed to create partnership"
      );
    }

    await this.notificationService.createNotification({
      sender: initiatorId,
      receiver: collaboratorId,
      action: "partnership_invitation",
      reference: partnershipId.toString(),
      referenceType: "Partnership",
    });

    return newPartnership;
  }
}

export default CreatePartnershipsAction;

import { IPlaceRepository } from "@/types/repositories/place.repository.types";
import { IUserRepository } from "@/types/repositories/user.repository.types";
import { Types } from "mongoose";
import { IDefaultSchedule, ICustomDate } from "@/types/models/place";
import {
  ConflictError,
  ERROR_CODES,
  NotFoundError,
} from "@/utils/errors";

export interface CreatePlaceInput {
  location: {
    type: "Point";
    coordinates: [number, number];
    label: string;
    id: string;
  };
  placeCategory: string;
  defaultSchedule?: IDefaultSchedule;
  customDates?: ICustomDate[];
}

export interface ICreatePlaceAction {
  execute(params: {
    placeData: CreatePlaceInput;
    userId: string;
  }): Promise<{ _id: string }>;
}

class CreatePlaceAction implements ICreatePlaceAction {
  constructor(
    private placeRepository: IPlaceRepository,
    private userRepository: IUserRepository
  ) {}

  async execute({
    placeData,
    userId,
  }: {
    placeData: CreatePlaceInput;
    userId: string;
  }): Promise<{ _id: string }> {
    const user = await this.userRepository.findOne({ _id: userId }, [
      "username",
      "place",
    ]);

    if (!user) {
      throw new NotFoundError(ERROR_CODES.USER_NOT_FOUND, "User not found");
    }

    // Business rule: users can only have 1 place
    if (user.place) {
      throw new ConflictError(
        ERROR_CODES.USER_ALREADY_HAS_PLACE,
        "User already has a place"
      );
    }

    const newPlace = {
      ...placeData,
      user: new Types.ObjectId(userId),
      placeCategory: new Types.ObjectId(placeData.placeCategory),
    };

    const placeId = await this.placeRepository.create(newPlace);

    // Set place to user's place field
    await this.userRepository.updateOne(userId, {
      place: placeId,
    } as any);

    return { _id: placeId.toString() };
  }
}

export default CreatePlaceAction;

import { IUserRepository } from "@/types/repositories/user.repository.types";
import { IPlaceRepository } from "@/types/repositories/place.repository.types";
import { IEventRepository } from "@/types/repositories/event.repository.types";
import { IPartnershipRepository } from "@/types/repositories/partnership.repository.types";
import { IEventBookingRepository } from "@/types/repositories/eventBooking.repository.types";
import { IEventInvitationRepository } from "@/types/repositories/eventInvitation.repository.types";
import { IFavoriteRepository } from "@/types/repositories/favorite.repository.types";
import { INotificationRepository } from "@/types/repositories/notification.repository.types";
import { IImageRepository } from "@/types/repositories/image.repository.types";
import CascadeDeleteService from "@/services/cascadeDeleteService";
import logger from "@/utils/logger";

export interface IDeleteAccountAction {
  execute(params: { userId: string }): Promise<void>;
}

class DeleteAccountAction implements IDeleteAccountAction {
  constructor(
    private userRepository: IUserRepository,
    private placeRepository: IPlaceRepository,
    private eventRepository: IEventRepository,
    private partnershipRepository: IPartnershipRepository,
    private eventBookingRepository: IEventBookingRepository,
    private eventInvitationRepository: IEventInvitationRepository,
    private favoriteRepository: IFavoriteRepository,
    private notificationRepository: INotificationRepository,
    private imageRepository: IImageRepository,
    private cascadeDeleteService: CascadeDeleteService
  ) {}

  async execute({ userId }: { userId: string }): Promise<void> {
    const user = await this.userRepository.findById(userId, ["_id"]);
    if (!user) {
      throw new Error("User not found");
    }

    // Places owned by the user (cascades to their events, reviews, bookings, images...)
    const userPlaces = await this.placeRepository.findAll({
      filters: { user: userId },
      project: ["_id"],
    });
    for (const place of userPlaces) {
      await this.cascadeDeleteService.deletePlace(place._id.toString());
    }
    logger.info(`Deleted ${userPlaces.length} places for user ${userId}`);

    // Events owned directly by the user
    const ownedEvents = await this.eventRepository.findAll({
      filters: { user: userId },
      project: ["_id"],
    });
    await this.cascadeDeleteService.deleteEvents(
      ownedEvents.map((event) => event._id.toString())
    );
    logger.info(`Deleted ${ownedEvents.length} owned events for user ${userId}`);

    // Remove user from event collaborators
    await this.eventRepository.updateMany(
      { "schedule.timeSlots.collaborators": userId },
      { $pull: { "schedule.$[].timeSlots.$[].collaborators": userId } } as any
    );

    // Data linking the user to other entities
    await this.partnershipRepository.deleteMany({
      $or: [{ initiator: userId }, { collaborator: userId }],
    });
    await this.eventInvitationRepository.deleteMany({
      $or: [{ initiator: userId }, { collaborator: userId }],
    });
    await this.eventBookingRepository.deleteMany({ user: userId });
    await this.favoriteRepository.deleteMany({ user: userId });
    await this.notificationRepository.deleteByUser(userId);

    // Images owned by the user or attached to their profile
    const imagesByOwner = await this.imageRepository.findAll({
      filters: { user: userId },
      project: ["_id"],
    });
    const imagesByReference = await this.imageRepository.findAll({
      filters: { reference: userId, referenceType: "User" },
      project: ["_id"],
    });
    const userImageIds = [
      ...new Set([
        ...imagesByOwner.map((img) => img._id.toString()),
        ...imagesByReference.map((img) => img._id.toString()),
      ]),
    ];
    await this.cascadeDeleteService.deleteImagesWithComments(userImageIds);

    await this.userRepository.deleteOne(userId);
    logger.info(`User account permanently deleted: ${userId}`);
  }
}

export default DeleteAccountAction;

import {
  IUserRepository,
  UserFilters,
} from "@/types/repositories/user.repository.types";
import { IUser } from "@/types/models/user";

export interface GetUsersInput {
  username?: string;
  userType?: "creator" | "guest";
  limit?: number;
  excludeIds?: string[];
}

export interface IGetUsersAction {
  execute(params: { filters?: GetUsersInput }): Promise<IUser[]>;
}

class GetUsersAction implements IGetUsersAction {
  private readonly project: (keyof IUser | string)[] = [
    "_id",
    "firstname",
    "lastname",
    "username",
    "userType",
    "description",
    "image.urls",
    "googlePictureUrl",
    "userCategory.name",
    "userCategory.type",
    "userCategory.type.name",
    "place.location",
    "place.placeCategory.name",
  ];

  constructor(private userRepository: IUserRepository) {}

  async execute({ filters }: { filters?: GetUsersInput }): Promise<IUser[]> {
    const queryFilters: UserFilters = {
      deleted: false,
    };

    if (filters?.username) {
      queryFilters.username = {
        $regex: filters.username,
        $options: "i",
      } as any;
    }

    if (filters?.excludeIds) {
      const excludeArray = Array.isArray(filters.excludeIds)
        ? filters.excludeIds
        : [filters.excludeIds];
      queryFilters._id = { $nin: excludeArray };
    }

    if (filters?.userType) {
      queryFilters.userType = filters.userType;
    }

    const users = await this.userRepository.findAll({
      filters: queryFilters,
      project: this.project,
      limit: filters?.limit || 10,
    });

    return users as IUser[];
  }
}

export default GetUsersAction;

import { Response, NextFunction, RequestHandler } from "express";
import { APIResponse } from "@/utils/response";
import { getParam } from "@/utils/request";
import { CustomRequest } from "@/types/custom";
import { IMessageRepository } from "@/types/repositories/message.repository.types";
import { isValidObjectId } from "mongoose";

class MessagesMiddleware {
  constructor(private messageRepository: IMessageRepository) {}

  ownership(): RequestHandler {
    return async (
      req: CustomRequest,
      res: Response,
      next: NextFunction
    ): Promise<void> => {
      try {
        const decoded = req.decoded!;
        const messageId = getParam(req.params, "messageId");

        if (!messageId) {
          APIResponse(res, null, "Message ID requis", 400);
          return;
        }

        if (!isValidObjectId(messageId)) {
          APIResponse(res, null, "ID de message invalide", 400);
          return;
        }

        const message = await this.messageRepository.findById(messageId, [
          "sender",
        ]);
        if (!message) {
          APIResponse(res, null, "Message non trouvé", 404);
          return;
        }

        if (message.sender?.toString() !== decoded.id) {
          APIResponse(
            res,
            null,
            "Vous n'êtes pas autorisé à modifier ou supprimer ce message",
            403
          );
          return;
        }

        req.message = message as any;
        next();
      } catch {
        APIResponse(
          res,
          null,
          "Erreur lors de la vérification de propriété",
          500
        );
      }
    };
  }
}

export default MessagesMiddleware;

import { model, Schema } from "mongoose";
import { IEventTimeSlot, IEventPeriod, IEvent } from "@/types/models/event";
import "../models/EventCategory";
import EventStatusService from "@/services/eventStatusService";
import { locationSchema } from "./Place";

const eventStatusService = new EventStatusService();

export const eventTimeSlotSchema = new Schema<IEventTimeSlot>({
  title: { type: String, required: true },
  startTime: { type: String, required: true },
  endTime: { type: String, required: true },
  collaborators: [
    {
      type: Schema.Types.ObjectId,
      ref: "User",
    },
  ],
});

export const customScheduleWithParticipantsSchema = new Schema<IEventPeriod>({
  startDate: { type: Date, required: true },
  endDate: { type: Date, required: true },
  timeSlots: [eventTimeSlotSchema],
});

export const eventSchema = new Schema<IEvent>(
  {
    name: {
      type: String,
      required: [true, "Please add a title"],
      trim: true,
    },
    description: {
      type: String,
      required: [true, "Please add a description"],
    },
    schedule: {
      type: [customScheduleWithParticipantsSchema],
      required: [true, "Please add a schedule"],
    },
    eventCategory: {
      type: Schema.Types.ObjectId,
      ref: "EventCategory",
      required: [true, "Please add an event category"],
    },
    user: {
      type: Schema.Types.ObjectId,
      ref: "User",
      required: [true, "Please add a user"],
    },
    place: {
      type: Schema.Types.ObjectId,
      ref: "Place",
      required: false,
      default: null,
    },
    location: {
      type: locationSchema,
      required: false,
      default: null,
    },
    online: { type: Boolean, default: false },
    image: {
      type: Schema.Types.ObjectId,
      ref: "Image",
      required: false,
    },
    status: {
      type: String,
      enum: ["cancelled", "full", "available"],
      default: "available",
    },
    lifecycleStatus: {
      type: String,
      enum: ["upcoming", "ongoing", "completed", "unvalid"],
      default: "unvalid",
    },
    dateRange: {
      firstDate: { type: Date, required: false },
      latestDate: { type: Date, required: false },
    },
    rating: { type: Number, default: 0 },
    isBookable: { type: Boolean, default: false },
    capacity: { type: Number, default: null, min: 1 },
    maxSeatsPerBooking: { type: Number, default: 1, min: 1 },
    deleted: { type: Boolean, default: false },
    deletedAt: { type: Date },
    deletedBy: { type: Schema.Types.ObjectId, ref: "User" },
    deleteReason: { type: String },
  },
  { timestamps: true }
);

eventSchema.pre("validate", function (next) {
  if (this.online) {
    this.place = null;
    this.location = null;
    return next();
  }

  if (!this.place && !this.location) {
    return next(new Error("Please add a place or a location"));
  }

  next();
});

eventSchema.pre("validate", function (next) {
  if (!this.isBookable) {
    return next();
  }

  if (typeof this.capacity === "number" && this.capacity < this.maxSeatsPerBooking) {
    return next(
      new Error(
        "Le nombre de places réservables par utilisateur ne peut pas dépasser la capacité totale"
      )
    );
  }

  next();
});

eventSchema.index({ "location.coordinates": "2dsphere" });

eventSchema.pre("save", function (next) {
  if (this.isModified("schedule") || this.isNew) {
    if (this.schedule && this.schedule.length > 0) {
      const { dateRange, lifecycleStatus } =
        eventStatusService.calculateEventStatus(this.schedule);
      this.dateRange = dateRange;
      this.lifecycleStatus = lifecycleStatus;
    }
  }
  next();
});

eventSchema.pre("findOneAndUpdate", function (next) {
  const update = this.getUpdate() as any;
  if (update && update.schedule) {
    const { dateRange, lifecycleStatus } =
      eventStatusService.calculateEventStatus(update.schedule);
    if (update.$set) {
      update.$set.dateRange = dateRange;
      update.$set.lifecycleStatus = lifecycleStatus;
    } else {
      update.dateRange = dateRange;
      update.lifecycleStatus = lifecycleStatus;
    }
  }
  next();
});

export default model<IEvent>("Event", eventSchema);

import { Schema, model } from "mongoose";
import AwsService from "@/services/awsService";
import logger from "@/utils/logger";

const awsService = new AwsService();

const imageSchema = new Schema(
  {
    urls: {
      original: { type: String, required: true },
      thumbnail: { type: String, required: true },
      medium: { type: String, required: true },
    },
    user: {
      type: Schema.Types.ObjectId,
      ref: "User",
    },
    reference: {
      type: Schema.Types.ObjectId,
      required: true,
      refPath: "referenceType",
    },
    referenceType: {
      type: String,
      required: true,
      enum: ["Place", "User", "Event", "Comment", "Review"],
    },
    type: {
      type: String,
      required: true,
      enum: ["profile", "cover", "gallery", "other"],
    },
    originalName: { type: String, required: true },
    size: { type: Number, required: true },
    mimetype: { type: String, required: true },
    deleted: { type: Boolean, default: false },
    deletedAt: { type: Date },
    deletedBy: { type: Schema.Types.ObjectId, ref: "User" },
    deleteReason: { type: String },
  },
  { timestamps: true }
);

imageSchema.virtual("signedUrls").get(function () {
  return this.urls;
});

imageSchema.post(
  ["find", "findOne", "findOneAndUpdate"],
  async function (docs) {
    if (!docs) return;

    const processDoc = async (doc: any) => {
      if (doc && doc.urls) {
        try {
          doc.urls.original = await awsService.generateSignedUrlFromFullUrl(
            doc.urls.original
          );
          doc.urls.thumbnail = await awsService.generateSignedUrlFromFullUrl(
            doc.urls.thumbnail
          );
          doc.urls.medium = await awsService.generateSignedUrlFromFullUrl(
            doc.urls.medium
          );
        } catch (error) {
          logger.error("Error signing image URLs:", error);
        }
      }
    };
    if (Array.isArray(docs)) {
      await Promise.all(docs.map(processDoc));
    } else {
      await processDoc(docs);
    }
  }
);

imageSchema.set("toJSON", { virtuals: true });
imageSchema.set("toObject", { virtuals: true });

export default model("Image", imageSchema);

