const PARIS_CENTER = { lng: 2.3522, lat: 48.8566 };

const defaultSchedule = {
  monday: { open: true, timeSlots: [{ startTime: "09:00", endTime: "18:00" }] },
  tuesday: {
    open: true,
    timeSlots: [{ startTime: "09:00", endTime: "18:00" }],
  },
